@using sv_f54400897d7c4f5abf4652038ee32570.Models

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepNum = i + 1;
        var status = GetStepStatus(stepIndex);

        <div class="step-item text-center flex-fill @status"
             @onclick="() => OnStepClick(stepIndex)"
             role="button">
            <div class="step-circle mx-auto mb-1 @status">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@stepNum</span>
                }
            </div>
            <small class="step-label">@StepNames[stepIndex]</small>
        </div>

        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector align-self-start mt-3 flex-fill">
                <hr class="@(stepIndex < CurrentStep ? "completed" : "")" />
            </div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepStatus(int index)
    {
        if (index == CurrentStep) return "active";
        if (index < CurrentStep) return "completed";
        return "future";
    }

    private async Task OnStepClick(int index)
    {
        if (index < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(index);
        }
    }
}

