{"file_text": "@using sv_f54400897d7c4f5abf4652038ee32570.Models

<h4 class="mb-3">Personal Information</h4>

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control @(Errors.ContainsKey("FullName") ? "is-invalid" : "")"
               @bind="Model.FullName" @bind:event="oninput" />
        @if (Errors.ContainsKey("FullName"))
        {
            <div class="invalid-feedback">@Errors["FullName"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email"
               class="form-control @(Errors.ContainsKey("Email") ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (Errors.ContainsKey("Email"))
        {
            <div class="invalid-feedback">@Errors["Email"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel"
               class="form-control @(Errors.ContainsKey("Phone") ? "is-invalid" : "")"
               @bind="Model.Phone" @bind:event="oninput" />
        @if (Errors.ContainsKey("Phone"))
        {
            <div class="invalid-feedback">@Errors["Phone"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control @(Errors.ContainsKey("Address") ? "is-invalid" : "")"
               @bind="Model.Address" @bind:event="oninput" />
        @if (Errors.ContainsKey("Address"))
        {
            <div class="invalid-feedback">@Errors["Address"]</div>
        }
    </div>
</div>

@if (!string.IsNullOrEmpty(GeneralError))
{
    <div class="alert alert-danger mt-3">@GeneralError</div>
}

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private Dictionary<string, string> Errors { get; set; } = new();
    private string? GeneralError { get; set; }
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();
        GeneralError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
            Errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            Errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            Errors["Phone"] = "Phone number is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            Errors["Address"] = "Address is required.";

        if (Errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                Errors["Email"] = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        catch
        {
            GeneralError = "An error occurred validating your email. Please try again.";
        }
        finally
        {
            IsValidating = false;
        }
    }
}
