@page "/apply"
@rendermode InteractiveServer
@using sv_f54400897d7c4f5abf4652038ee32570.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (_submitted)
    {
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem;">✅</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@_applicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" OnStepSelected="GoToStep" />

        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="_references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@_coverLetter"
                                 CoverLetterChanged="v => _coverLetter = v"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="@_coverLetter"
                            OnEdit="GoToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int _currentStep;
    private bool _submitted;
    private int _applicationId;

    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep() => _currentStep++;
    private void PreviousStep() => _currentStep--;
    private void GoToStep(int step) => _currentStep = step;

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            _personalInfo.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter
        );

        _applicationId = await ApplicationService.SubmitApplicationAsync(application);
        _submitted = true;
    }
}

.step-indicator {
    position: relative;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-circle.active {
    background-color: #0d6efd;
    color: white;
}

.step-circle.completed {
    background-color: #198754;
    color: white;
    cursor: pointer;
}

.step-circle.future {
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item {
    min-width: 0;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.future {
    opacity: 0.5;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.step-connector hr {
    border: none;
    border-top: 2px solid #e9ecef;
    margin: 0.5rem 0;
}

.step-connector hr.completed {
    border-top-color: #198754;
}

