toolArgs.file_text:
.step-indicator {
    position: relative;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-circle.active {
    background-color: #0d6efd;
    color: white;
}

.step-circle.completed {
    background-color: #198754;
    color: white;
    cursor: pointer;
}

.step-circle.future {
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item {
    min-width: 0;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.future {
    opacity: 0.5;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.step-connector hr {
    border: none;
    border-top: 2px solid #e9ecef;
    margin: 0.5rem 0;
}

.step-connector hr.completed {
    border-top-color: #198754;
}

